public static void CheckIsDerivedFrom(this Type derivedType, Type baseType)
    {
        if (!baseType.IsAssignableFrom(derivedType) && !derivedType.IsGenericTypeDefinition && !baseType.IsGenericTypeDefinition)
        {
            throw new ArgumentOutOfRangeException(nameof(derivedType), $"{derivedType} is not derived from {baseType}.");
        }
    }

public static int IndexOf<T>(this IEnumerable<T> collection, Func<T, bool> predicate)
        {
            int index = 0;
            foreach (T value in collection)
            {
                if (predicate(value))
                {
                    return index;
                }

                index++;
            }

            return -1;
        }

protected bool Equals(NamingStrategy? other)
        {
            if (other == null)
            {
                return false;
            }

            return GetType() == other.GetType() &&
                ProcessDictionaryKeys == other.ProcessDictionaryKeys &&
                ProcessExtensionDataNames == other.ProcessExtensionDataNames &&
                OverrideSpecifiedNames == other.OverrideSpecifiedNames;
        }

public static void ForEach<T>(this IEnumerable<T> source, Action<T> action)
        {
            if (source == null) throw new ArgumentNullException(nameof(source));
            if (action == null) throw new ArgumentNullException(nameof(action));

            foreach (var element in source)
                action(element);
        }

public static void ForEach<T>(this IEnumerable<T> source, Action<T, int> action)
        {
            if (source == null) throw new ArgumentNullException(nameof(source));
            if (action == null) throw new ArgumentNullException(nameof(action));

            var index = 0;
            foreach (var element in source)
                action(element, index++);
        }

static int CountUpTo<T>(this IEnumerable<T> source, int max)
        {
            if (source == null) throw new ArgumentNullException(nameof(source));
            if (max < 0) throw new ArgumentOutOfRangeException(nameof(max), "The maximum count argument cannot be negative.");

            var count = 0;

            using var e = source.GetEnumerator();
            while (count < max && e.MoveNext())
                count++;

            return count;
        }

private void PrecalculateVolatileLayoutsWithLock(LogEventInfo logEvent)
        {
            lock (SyncRoot)
            {
                using (var targetBuilder = ReusableLayoutBuilder.Allocate())
                {
                    foreach (Layout layout in _allLayouts)
                    {
                        targetBuilder.Result.ClearBuilder();
                        layout.PrecalculateBuilder(logEvent, targetBuilder.Result);
                    }
                }
            }
        }

public bool IsLoggingEnabledForLevel(LogLevel level)
        {
            if (level == LogLevel.Off)
            {
                return false;
            }

            var currentLogLevels = _logLevelFilter.LogLevels;
            return currentLogLevels[level.Ordinal];
        }

protected override void Append(StringBuilder builder, LogEventInfo logEvent)
        {
            var value = GetValue(logEvent);
            if (_utcRoundRoundTrip && value.Kind != DateTimeKind.Local)
            {
                builder.AppendXmlDateTimeUtcRoundTripFixed(value);
            }
            else
            {
                var formatProvider = GetFormatProvider(logEvent, Culture);
                builder.Append(GetStringValue(value, formatProvider));
            }
        }

private DateTime GetValue(LogEventInfo logEvent)
        {
            var timestamp = logEvent.TimeStamp;
            if (_universalTime.HasValue)
            {
                if (_universalTime.Value)
                    timestamp = timestamp.ToUniversalTime();
                else if (timestamp.Kind == DateTimeKind.Utc)
                    timestamp = timestamp.ToLocalTime();
            }
            return timestamp;
        }

private static bool IsLowTimeResolutionLayout(string dateTimeFormat)
        {
            for (int i = 0; i < dateTimeFormat.Length; ++i)
            {
                char ch = dateTimeFormat[i];
                if (char.IsLetter(ch) && _lowTimeResolutionChars.IndexOf(ch) < 0)
                    return false;
            }
            return true;
        }

public void AddTarget(Target target)
        {
            Guard.ThrowIfNull(target);

            InternalLogger.Debug("Adding target {0}(Name={1})", target.GetType(), target.Name);

            if (string.IsNullOrEmpty(target.Name)) { throw new ArgumentException(nameof(target) + ".Name cannot be empty", nameof(target)); }

            AddTargetThreadSafe(target, target.Name);
        }

private void DecrementExecutionGroupCount(string normalizedGroup)
    {
        int newCount = runningExecutionGroupCounts.AddOrUpdate(normalizedGroup, 0, (_, c) => Math.Max(c - 1, 0));
        // Remove zero entries to prevent unbounded growth with high-cardinality group names
        if (newCount <= 0)
        {
            runningExecutionGroupCounts.TryRemove(new KeyValuePair<string, int>(normalizedGroup, 0));
        }
    }

public TriggerBuilder GetTriggerBuilder()
    {
        return TriggerBuilder.Create()
            .ForJob(JobKey)
            .ModifiedByCalendar(CalendarName)
            .UsingJobData(JobDataMap)
            .WithDescription(Description)
            .WithExecutionGroup(ExecutionGroup)
            .EndAt(EndTimeUtc)
            .WithIdentity(Key)
            .WithPriority(Priority)
            .StartAt(StartTimeUtc)
            .WithSchedule(GetScheduleBuilder());
    }

public virtual async ValueTask<IOperableTrigger?> RetrieveTrigger(TriggerKey triggerKey, CancellationToken cancellationToken = default)
    {
        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
        try
        {
            triggersByKey.TryGetValue(triggerKey, out var tw);
            return (IOperableTrigger?) tw?.Trigger.Clone();
        }
        finally
        {
            lockObject.Release();
        }
    }

public override DateTimeOffset StartTimeUtc
    {
        get => startTimeUtc;
        set
        {
            DateTimeOffset? eTime = EndTimeUtc;
            if (eTime.HasValue && eTime.Value < value)
            {
                Throw.ArgumentException("End time cannot be before start time");
            }

            // round off millisecond...
            DateTimeOffset dt = new DateTimeOffset(value.Year, value.Month, value.Day, value.Hour, value.Minute, value.Second, value.Offset);
            startTimeUtc = dt;
        }
    }

public static ReactiveCommand<Unit, Unit> Create(
    Action execute,
    IObservable<bool>? canExecute,
    IScheduler? outputScheduler)
{
    ArgumentExceptionHelper.ThrowIfNull(execute);

    return new(
        _ => new SyncExecuteObservable<Unit>(() =>
        {
            execute();
            return Unit.Default;
        }),
        canExecute,
        outputScheduler);
}

public static ReactiveCommand<Unit, TResult> CreateRunInBackground<TResult>(
    Func<TResult> execute,
    IObservable<bool>? canExecute,
    IScheduler? backgroundScheduler,
    IScheduler? outputScheduler)
{
    ArgumentExceptionHelper.ThrowIfNull(execute);

    return CreateFromObservable(
        () => new StartObservable<TResult>(execute, backgroundScheduler ?? RxSchedulers.TaskpoolScheduler),
        canExecute,
        outputScheduler);
}

public static ReactiveCommand<TParam, TResult> CreateRunInBackground<TParam, TResult>(
    Func<TParam, TResult> execute,
    IObservable<bool>? canExecute,
    IScheduler? backgroundScheduler,
    IScheduler? outputScheduler)
{
    ArgumentExceptionHelper.ThrowIfNull(execute);

    return CreateFromObservable<TParam, TResult>(
        p => new StartObservable<TResult>(() => execute(p), backgroundScheduler ?? RxSchedulers.TaskpoolScheduler),
        canExecute,
        outputScheduler);
}

