public static void ShouldBeInRange<T>([DisallowNull] this T actual, T? from, T? to, string? customMessage = null,
        [CallerArgumentExpression(nameof(actual))] string? actualExpression = null)
        where T : IComparable<T>
    {
        actual.AssertAwesomely(v => Is.InRange(v, from, to), actual, new { from, to }, customMessage, actualExpression: actualExpression);
    }

public static T ShouldHaveSingleItem<T>([NotNull] this IEnumerable<T>? actual, string? customMessage = null,
        [CallerArgumentExpression(nameof(actual))] string? actualExpression = null)
    {
        if (actual == null || actual.Count() != 1)
            throw new ShouldAssertException(new ExpectedShouldlyMessage(actual, customMessage, actualExpression: actualExpression).ToString());

        return actual.Single();
    }

public ConstructorInfo? FindExplicitConstructor()
        {
            var constructors = _type.GetConstructors(BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
            var withAttr = constructors.Where(c => c.GetCustomAttributes(typeof(ExplicitConstructorAttribute), true).Length > 0).ToList();

            if (withAttr.Count == 1)
            {
                return withAttr[0];
            }

            return null;
        }

public void Dispose()
            {
                if (reader is not null)
                {
                    if (!reader.IsClosed) Command?.Cancel();
                    reader.Dispose();
                    reader = null!;
                }
                if (Command is not null)
                {
                    Command.Dispose();
                    Command = null!;
                }
                GC.SuppressFinalize(this);
            }

private static bool IsNull(JToken token)
        {
            if (token.Type == JTokenType.Null)
            {
                return true;
            }

            if (token is JValue v && v.Value == null)
            {
                return true;
            }

            return false;
        }

public static IEnumerable<TResult> GenerateByIndex<TResult>(Func<int, TResult> generator)
        {
            if (generator == null) throw new ArgumentNullException(nameof(generator));

            return MoreEnumerable.Sequence(0, int.MaxValue)
                                 .Select(generator);
        }

public static IEnumerable<T> Shuffle<T>(this IEnumerable<T> source, Random rand)
        {
            if (source == null) throw new ArgumentNullException(nameof(source));
            if (rand == null) throw new ArgumentNullException(nameof(rand));

            return RandomSubsetImpl(source, rand, subsetSize: null);
        }

internal static string ThrowIfNullOrEmpty(
    string arg,
    [CallerArgumentExpression("arg")] string param = "")
{
    if (string.IsNullOrEmpty(arg))
        throw new ArgumentNullException(string.IsNullOrEmpty(param) ? nameof(arg) : param);

    return arg;
}

internal static bool TryCallSiteClassNameOptimization(StackTraceUsage stackTraceUsage, LogEventInfo logEvent)
        {
            if ((stackTraceUsage & (StackTraceUsage.WithCallSiteClassName | StackTraceUsage.WithStackTrace)) != StackTraceUsage.WithCallSiteClassName)
                return false;

            if (string.IsNullOrEmpty(logEvent.CallSiteInformation?.CallerFilePath))
                return false;

            if (logEvent.HasStackTrace)
                return false;

            return true;
        }

protected virtual void WriteAsyncThreadSafe(AsyncLogEventInfo logEvent)
        {
            lock (SyncRoot)
            {
                if (!IsInitialized)
                {
                    // In case target was Closed
                    logEvent.Continuation(null);
                    return;
                }

                Write(logEvent);
            }
        }
